  ('medical-tech-moex-21728', 'medical-tech', 'medical-tech-moex-092-5c00801d', 'sub-medical-tech-13', NULL, 'single_choice', '以直接抹片觀察寄生蟲，若以碘溶液取代生理食鹽水，其結果如何？ 會使蠕蟲卵保持較佳型態 可清楚辨識阿米巴囊體中的類染色質體 (Chromatoid bodies) 會使阿米巴滋養體失去活動性 較難以辨識原蟲囊體的核構造', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:18+00:00", "source_pdf_sha1": "0606f48555ed", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "105", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床鏡檢學(包括寄生蟲學)", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 67, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
